          animation: clearBounce 0.5s ease;
          box-shadow: 0 0 24px rgba(240,192,64,0.2);
          text-shadow: 0 0 8px rgba(240,192,64,0.3);
        }
        @keyframes clearBounce {
          0% { transform: scale(0.9); opacity: 0; }
          60% { transform: scale(1.05); }
          100% { transform: scale(1); opacity: 1; }
        }

        /* ─── 造字工坊按鈕（鍛造爐風格） ─── */
        .forge-btn {
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 4px;
          width: 100%;
          padding: 18px 24px;
          margin-top: 12px;
          border-radius: 14px;
          border: 2px solid rgba(230,126,34,0.4);
          background: linear-gradient(135deg, #1a0e05, #2d1f0e, #3d2510);
          color: #f0c040;
          font-family: inherit;
          font-size: 1.15rem;
          font-weight: 700;
          cursor: pointer;
          transition: all 0.3s;
          letter-spacing: 2px;
          text-shadow: 0 0 8px rgba(240,192,64,0.3);
          box-shadow: 0 4px 16px rgba(0,0,0,0.4), inset 0 1px 0 rgba(230,126,34,0.2);
          position: relative;
          overflow: hidden;
        }
        .forge-btn::before {
          content: '';
          position: absolute;
          top: 0; left: 0; right: 0;
          height: 1px;
          background: linear-gradient(90deg, transparent, rgba(230,126,34,0.5), transparent);
        }
        .forge-btn:hover {
          transform: translateY(-2px);
          box-shadow: 0 8px 28px rgba(230,126,34,0.3), 0 0 20px rgba(230,126,34,0.15);
          border-color: rgba(230,126,34,0.6);
        }
        .forge-btn-sub {
          font-size: 0.78rem;
          font-weight: 400;
          color: rgba(232,213,179,0.5);
          letter-spacing: 1px;
          text-shadow: none;
        }

        /* ─── 造字工坊卡片 ─── */
        .forge-card {
          background: linear-gradient(135deg, #3d2a14, #2d1f0e) !important;
          border: 2px solid rgba(230,126,34,0.3) !important;
          box-shadow: 0 8px 32px rgba(0,0,0,0.4), inset 0 0 30px rgba(230,126,34,0.05) !important;
        }
        .forge-radical-display {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 12px;
          margin: 20px 0 16px;
          flex-wrap: wrap;
        }
        .forge-radical-char {
          font-size: 3.5rem;
          font-weight: 900;
          color: #e67e22;
          line-height: 1;
          text-shadow: 0 0 16px rgba(230,126,34,0.5);
        }
        .forge-plus, .forge-equals {
          font-size: 2rem;
          color: rgba(232,213,179,0.4);
          font-weight: 300;
        }
        .forge-mystery {
          font-size: 3.5rem;
          color: #f0c040;
          font-weight: 900;
          line-height: 1;
          animation: mysteryPulse 1.5s infinite;
          text-shadow: 0 0 20px rgba(240,192,64,0.5);
        }
        @keyframes mysteryPulse {
          0%, 100% { opacity: 1; text-shadow: 0 0 20px rgba(240,192,64,0.5); }
          50% { opacity: 0.4; text-shadow: 0 0 8px rgba(240,192,64,0.2); }
        }
        .forge-result-char {
          font-size: 3.5rem;
          font-weight: 900;
          color: #2ecc71;
          line-height: 1;
          text-shadow: 0 0 16px rgba(46,204,113,0.5);
        }
        .forge-reveal {
          margin-top: 12px;
          padding: 10px 16px;
          background: rgba(46,204,113,0.08);
          border: 1px solid rgba(46,204,113,0.2);
          border-radius: 8px;
          animation: revealFade 0.4s ease;
        }
        .forge-reveal-text {
          font-size: 1.1rem;
          color: var(--ink, #e8d5b3);
        }
        .forge-reveal-text strong {
          color: #2ecc71;
          font-size: 1.4rem;
          text-shadow: 0 0 8px rgba(46,204,113,0.4);
        }
        .forge-reveal-zy {
          display: flex;
          justify-content: center;
          margin-top: 8px;
          animation: revealFade 0.4s ease;
        }
        .forge-reveal-zy .vzy { color: #2ecc71; }
        @keyframes revealFade {
          from { opacity: 0; transform: translateY(8px); }
          to { opacity: 1; transform: translateY(0); }
        }

        /* ─── 鍛造歷史紀錄 ─── */
        .forge-history {
          margin-top: 16px;
          padding: 14px;
          background: linear-gradient(135deg, var(--parchment-light, #3d2a14), var(--parchment, #2d1f0e));
          border-radius: 14px;
          border: 1.5px solid rgba(230,126,34,0.2);
        }
        .forge-history-title {
          font-size: 0.9rem;
          color: #e67e22;
          margin-bottom: 10px;
          text-shadow: 0 0 6px rgba(230,126,34,0.3);
        }
        .forge-history-list {
          display: flex;
          flex-direction: column;
          gap: 6px;
        }
        .forge-history-item {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
          padding: 8px 12px;
          background: rgba(0,0,0,0.2);
          border-radius: 8px;
          border: 1px solid rgba(240,192,64,0.08);
          animation: revealFade 0.3s ease;
        }
        .fh-formula {
          font-size: 0.95rem;
          color: rgba(232,213,179,0.7);
        }
        .fh-eq {
          color: rgba(232,213,179,0.3);
          font-size: 0.9rem;
        }
        .fh-result {
          font-size: 1.4rem;
          font-weight: 900;
          color: #2ecc71;
          font-family: 'Noto Serif TC', serif;
          text-shadow: 0 0 6px rgba(46,204,113,0.3);
        }
        .forge-history-item .vzy {
          color: rgba(232,213,179,0.6);
        }
        .forge-history-final {
          border-color: rgba(240,192,64,0.25);
        }
        .forge-history-final .forge-history-title {
          color: #f0c040;
        }
